// ======================================================
// EXTRATOR OCR - RECIBO DE PAGAMENTO AO MEDICO
// ✅ Lê retorno do OCR/Mistral
// ✅ Extrai pacientes da tabela markdown
// ✅ Corrige tabela com coluna vazia entre Procedimentos e Convênio
// ✅ Retorna no padrão para comparação com COMPUTADOR DO POSTO
// ======================================================

const entrada = $input.first().json;
const input = Array.isArray(entrada) ? entrada[0] : entrada;

// ======================================================
// 1. PEGA NOME DO ARQUIVO
// ======================================================

let nomeArquivo = "";

try {
  nomeArquivo = String($("ENVIO").first().json.name || "");
} catch (e) {
  nomeArquivo = String(input.name || input.fileName || "");
}

// ======================================================
// 2. PEGA TEXTO OCR
// ======================================================

const partesTexto = [];

if (input.markdown) partesTexto.push(String(input.markdown));
if (input.extractedText) partesTexto.push(String(input.extractedText));
if (input.text) partesTexto.push(String(input.text));
if (input.output) partesTexto.push(String(input.output));
if (input.response) partesTexto.push(String(input.response));

if (Array.isArray(input.pages)) {
  for (const p of input.pages) {
    if (p.markdown) partesTexto.push(String(p.markdown));
    if (p.text) partesTexto.push(String(p.text));
  }
}

const textoOCR = partesTexto
  .filter(Boolean)
  .join("\n")
  .replace(/\\n/g, "\n")
  .replace(/\r/g, "\n");

if (!textoOCR.trim()) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum texto OCR encontrado.",
        nomeArquivo
      }
    }
  ];
}

// ======================================================
// 3. FUNÇÕES AUXILIARES
// ======================================================

function limpar(valor) {
  return String(valor ?? "")
    .replace(/\u00A0/g, " ")
    .replace(/\t/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizar(valor) {
  return limpar(valor)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .trim();
}

function converterValor(valor) {
  let v = limpar(valor);

  if (!v) return 0;

  v = v
    .replace(/R\$/gi, "")
    .replace(/[^\d.,-]/g, "")
    .trim();

  if (!v) return 0;

  if (/^\d{1,3}(\.\d{3})*,\d{2}$/.test(v)) {
    v = v.replace(/\./g, "").replace(",", ".");
  } else {
    v = v.replace(",", ".");
  }

  const numero = Number(v);
  return Number.isFinite(numero) ? numero : 0;
}

function extrairPosto(nome, texto) {
  const fonte = `${nome || ""}\n${texto || ""}`;

  let m = fonte.match(/\bP\s*0*(\d{1,5})\b/i);
  if (m) return m[1];

  m = fonte.match(/\bPOSTO\s*0*(\d{1,5})\b/i);
  if (m) return m[1];

  return "";
}

function extrairDataArquivoOuTexto(nome, texto) {
  const fonte = `${nome || ""}\n${texto || ""}`;

  let m = fonte.match(/\b(\d{2})\/(\d{2})\/(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  m = fonte.match(/\b(\d{2})\.(\d{2})\.(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  m = fonte.match(/\b(\d{2})-(\d{2})-(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  return "";
}

function extrairMedico(texto) {
  const m = texto.match(/M[eé]dico:\s*([^\n\r]+)/i);
  return m ? limpar(m[1]).toUpperCase() : "";
}

function extrairNumeroRecibo(texto) {
  const m = texto.match(/Recibo\s+nr\.?\s*([0-9]+)/i);
  return m ? limpar(m[1]) : "";
}

function extrairDataCaixa(texto) {
  const m = texto.match(/Data\s+do\s+Caixa:\s*(\d{2}\/\d{2}\/\d{4})/i);
  return m ? limpar(m[1]) : "";
}

function extrairDataPagamento(texto) {
  const m = texto.match(/Data\s+de\s+Pagamento:\s*(\d{2}\/\d{2}\/\d{4})\s+(\d{2}:\d{2})h?/i);

  return {
    dataPagamento: m ? limpar(m[1]) : "",
    horaPagamento: m ? limpar(m[2]) : ""
  };
}

function extrairFormaPagamento(texto) {
  const m = texto.match(/Forma\s+de\s+Pagamento:\s*([^\n\r]+)/i);
  return m ? limpar(m[1]).toUpperCase() : "";
}

function separarProcedimentos(textoProcedimentos) {
  const texto = limpar(textoProcedimentos);

  if (!texto) return [];

  const procedimentos = [];
  let atual = "";
  let nivelParenteses = 0;

  for (let i = 0; i < texto.length; i++) {
    const char = texto[i];

    if (char === "(") {
      nivelParenteses++;
      atual += char;
      continue;
    }

    if (char === ")") {
      nivelParenteses = Math.max(0, nivelParenteses - 1);
      atual += char;
      continue;
    }

    if (char === "," && nivelParenteses === 0) {
      const proc = limpar(atual);
      if (proc) procedimentos.push(proc.toUpperCase());
      atual = "";
      continue;
    }

    atual += char;
  }

  const ultimo = limpar(atual);
  if (ultimo) procedimentos.push(ultimo.toUpperCase());

  return procedimentos.filter(Boolean);
}

function ehLinhaSeparadora(cols) {
  return cols.every(c => /^-+$/.test(limpar(c).replace(/\s/g, "")));
}

function ehLinhaCabecalho(cols) {
  const junta = normalizar(cols.join(" "));
  return (
    junta.includes("ATEND") ||
    junta.includes("PACIENTE") ||
    junta.includes("PROCEDIMENTOS") ||
    junta.includes("CONVENIO") ||
    junta.includes("VALOR MEDICO")
  );
}

function ehNomePaciente(valor) {
  const texto = limpar(valor);
  const n = normalizar(texto);

  if (!texto || texto.length < 5) return false;
  if (/\d/.test(texto)) return false;

  const bloqueados = [
    "PACIENTE",
    "TOTAL",
    "TAXAS",
    "LANCAMENTO",
    "ATEND",
    "PROCEDIMENTOS",
    "CONVENIO",
    "VALOR MEDICO",
    "QTD VOLTA",
    "QTD ATEND"
  ];

  return !bloqueados.some(p => n.includes(p));
}

function extrairDadosLinhaRecibo(cols) {
  let c = cols.map(limpar);

  if (c[0] === "") c.shift();
  if (c[c.length - 1] === "") c.pop();

  if (ehLinhaSeparadora(c)) return null;
  if (ehLinhaCabecalho(c)) return null;

  // Remove colunas vazias criadas pelo OCR/markdown
  c = c.filter((valor, idx) => {
    // mantém primeira coluna mesmo se vier estranha, mas remove vazios do meio
    return limpar(valor) !== "";
  });

  if (c.length < 5) return null;

  const atendimento = limpar(c[0]);
  const paciente = limpar(c[1]);
  const procedimentos = limpar(c[2]);

  // Convênio e valor ficam nas duas últimas colunas
  const convenio = limpar(c[c.length - 2]);
  const valorTexto = limpar(c[c.length - 1]);

  if (!/^\d+$/.test(atendimento)) return null;
  if (!ehNomePaciente(paciente)) return null;
  if (!procedimentos) return null;
  if (!convenio) return null;
  if (!valorTexto) return null;

  return {
    atendimento,
    paciente: paciente.toUpperCase(),
    procedimentos,
    convenio: convenio.toUpperCase(),
    valorTexto,
    valor: converterValor(valorTexto)
  };
}

// ======================================================
// 4. DADOS GERAIS
// ======================================================

const medico = extrairMedico(textoOCR);
const numeroRecibo = extrairNumeroRecibo(textoOCR);
const dataCaixa = extrairDataCaixa(textoOCR);
const { dataPagamento, horaPagamento } = extrairDataPagamento(textoOCR);
const formaPagamento = extrairFormaPagamento(textoOCR);

const posto = extrairPosto(nomeArquivo, textoOCR);
const data = dataCaixa || dataPagamento || extrairDataArquivoOuTexto(nomeArquivo, textoOCR);

// ======================================================
// 5. EXTRAI PACIENTES DA TABELA
// ======================================================

const linhas = textoOCR
  .split(/\n+/)
  .map(l => limpar(l))
  .filter(Boolean);

const pacientes = [];

for (const linha of linhas) {
  if (!linha.includes("|")) continue;

  let cols = linha.split("|").map(c => limpar(c));

  const dados = extrairDadosLinhaRecibo(cols);
  if (!dados) continue;

  const exames = separarProcedimentos(dados.procedimentos);
  if (exames.length === 0) continue;

  pacientes.push({
    atendimento: dados.atendimento,
    PACIENTE: dados.paciente,
    EXAMES: exames,
    EXAMES_TEXTO: exames.join(", "),
    QTD_EXAMES: exames.length,
    CONVENIO: dados.convenio,
    VALOR: dados.valor,
    valorLinha: dados.valorTexto
  });
}

// ======================================================
// 6. SE NÃO ENCONTRAR PACIENTES
// ======================================================

if (pacientes.length === 0) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum paciente foi extraído da tabela do recibo.",
        medico,
        numeroRecibo,
        posto,
        data,
        dataCaixa,
        dataPagamento,
        horaPagamento,
        formaPagamento,
        nomeArquivo,
        debug: {
          totalLinhas: linhas.length,
          linhasComPipe: linhas.filter(l => l.includes("|")).length,
          primeirasLinhasComPipe: linhas.filter(l => l.includes("|")).slice(0, 15),
          textoOCRInicio: textoOCR.slice(0, 1500)
        }
      }
    }
  ];
}

// ======================================================
// 7. RETORNO FINAL NO PADRÃO DE COMPARAÇÃO
// ======================================================

return pacientes.map((p, index) => ({
  json: {
    sucesso: true,
    categoria: "RECIBO DE PAGAMENTO AO MEDICO",

    PACIENTE: p.PACIENTE,
    EXAMES: p.EXAMES,
    EXAMES_TEXTO: p.EXAMES_TEXTO,
    QTD_EXAMES: p.QTD_EXAMES,
    VALOR: p.VALOR,

    posto,
    data,

    codIntegracao: "",
    codAtend: p.atendimento,

    medico,
    numeroRecibo,
    dataCaixa,
    dataPagamento,
    horaPagamento,
    formaPagamento,
    convenio: p.CONVENIO,
    valorLinha: p.valorLinha,

    _idx: index + 1,
    _totalPacientes: pacientes.length
  }
}));

// ======================================================
// EXTRATOR OCR - RELATÓRIO DE MOTOQUEIROS / LABOVIDA
// ✅ Retorna 1 item por paciente
// ✅ Categoria fixa: (+)COMPUTADOR DO POSTO
// ✅ Extrai: posto, data, codigo, paciente, exames
// ✅ Funciona com tabela markdown com | e também com texto solto sem |
// ✅ Corrige BHCG, AHCV e CTFT
// ✅ VALOR sempre 0
// ======================================================

const input = $input.first().json;

// ======================================================
// 1. PEGA NOME DO ARQUIVO
// ======================================================

let nomeArquivo = "";

try {
  nomeArquivo = String($("ENVIO").first().json.name || "");
} catch (e) {
  nomeArquivo = String(input.name || input.fileName || "");
}

// ======================================================
// 2. PEGA TEXTO OCR
// ======================================================

const partesTexto = [];

if (input.markdown) partesTexto.push(String(input.markdown));
if (input.extractedText) partesTexto.push(String(input.extractedText));
if (input.text) partesTexto.push(String(input.text));

if (Array.isArray(input.pages)) {
  for (const p of input.pages) {
    if (p.markdown) partesTexto.push(String(p.markdown));
    if (p.text) partesTexto.push(String(p.text));
  }
}

let textoOCR = partesTexto
  .filter(Boolean)
  .join("\n")
  .replace(/\\n/g, "\n")
  .replace(/\r/g, "\n");

if (!textoOCR.trim()) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum texto OCR encontrado.",
        nomeArquivo
      }
    }
  ];
}

// ======================================================
// 3. FUNÇÕES AUXILIARES
// ======================================================

function limpar(valor) {
  return String(valor ?? "")
    .replace(/\u00A0/g, " ")
    .replace(/\t/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizar(valor) {
  return limpar(valor)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .trim();
}

function extrairPosto(nomeArquivo, texto) {
  const fonte = `${nomeArquivo || ""}\n${texto || ""}`;

  let m = fonte.match(/\bP\s*0*(\d{1,5})\b/i);
  if (m) return m[1];

  m = fonte.match(/\bPOSTO\s*0*(\d{1,5})\b/i);
  if (m) return m[1];

  return "";
}

function extrairData(nomeArquivo, texto) {
  const fonte = `${nomeArquivo || ""}\n${texto || ""}`;

  let m = fonte.match(/\b(\d{2})\.(\d{2})\.(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  m = fonte.match(/\b(\d{2})\/(\d{2})\/(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  m = fonte.match(/\b(\d{2})-(\d{2})-(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  return "";
}

function ehDataBR(valor) {
  return /^\d{2}\/\d{2}\/\d{4}$/.test(limpar(valor));
}

function ehCodigo(valor) {
  return /^\d{5,}$/.test(limpar(valor));
}

function removerColchetes(texto) {
  return String(texto || "")
    .replace(/\[[^\]]*]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function ehNomePaciente(valor) {
  const texto = limpar(valor);
  const n = normalizar(texto);

  if (!texto) return false;
  if (texto.length < 5) return false;
  if (/\d/.test(texto)) return false;

  const bloqueados = [
    "LABOVIDA",
    "RELATORIO",
    "RELATÓRIO",
    "MOTOQUEIROS",
    "RESUMO",
    "PACIENTES",
    "PACIENTE",
    "EXAME",
    "EXAMES",
    "USUARIO",
    "USUÁRIO",
    "DATA DE IMPRESSAO",
    "DATA DE IMPRESSÃO",
    "CODIGO",
    "CÓDIGO"
  ];

  return !bloqueados.some(b => n.includes(normalizar(b)));
}

// ======================================================
// 4. SIGLAS DE EXAMES
// ======================================================

const SIGLAS_EXAMES = [
  "25OHD",
  "AUR",
  "B12",
  "CA",
  "CRE",
  "CTF",
  "CTFT",
  "GLIS",
  "HB1AC",
  "HBA1C",
  "HP",
  "IONO",
  "SU",
  "TRI",
  "TSH",
  "URE",
  "COAGU",
  "HEMO",
  "TPAE",
  "K",
  "FOSFO",
  "ALBUM",
  "TTPA",
  "NA",
  "MG",
  "PAPA",
  "GLI",
  "COLT",
  "VDRL",
  "T4L",
  "TGO",
  "TGP",
  "HIV",
  "HBSAG",
  "BETA",
  "HCG",
  "BHCG",
  "AHCV",
  "ANTI-HCV",
  "ANTI HCV"
];

const SET_SIGLAS = new Set(SIGLAS_EXAMES.map(s => normalizarExameBase(s)));

function normalizarExameBase(exame) {
  const n = normalizar(exame);

  if (!n) return "";

  if (n === "HBA1C") return "HB1AC";
  if (n === "GLI") return "GLIS";
  if (n === "BETA") return "BHCG";
  if (n === "HCG") return "BHCG";
  if (n === "BETA HCG") return "BHCG";
  if (n === "ANTI HCV") return "AHCV";
  if (n === "ANTI-HCV") return "AHCV";

  return n;
}

function normalizarExame(exame) {
  const n = normalizar(exame);

  if (!n) return "";

  if (n === "HBA1C") return "HB1AC";
  if (n === "GLI") return "GLIS";
  if (n === "BETA") return "BHCG";
  if (n === "HCG") return "BHCG";
  if (n === "BETA HCG") return "BHCG";
  if (n === "ANTI HCV") return "AHCV";
  if (n === "ANTI-HCV") return "AHCV";

  return n;
}

function ehTokenExame(token) {
  const t = normalizarExame(token);
  return SET_SIGLAS.has(t);
}

function separarExames(textoExames) {
  let texto = removerColchetes(textoExames);

  if (!texto) return [];

  texto = texto
    .replace(/[;|]/g, " ")
    .replace(/,/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  const tokens = texto
    .split(/\s+/)
    .map(t => normalizarExame(t))
    .filter(Boolean)
    .filter(t => !/^\d+([.,]\d+)?$/.test(t));

  const exames = [];

  for (const token of tokens) {
    if (ehTokenExame(token)) {
      exames.push(token);
    }
  }

  return [...new Set(exames)];
}

function linhaIgnorada(linha) {
  const n = normalizar(linha);

  if (!n) return true;
  if (n.includes("---")) return true;
  if (n.includes("LABOVIDA")) return true;
  if (n.includes("RELATORIO")) return true;
  if (n.includes("MOTOQUEIROS")) return true;
  if (n.includes("RESUMO")) return true;
  if (n.includes("PACIENTES")) return true;
  if (n.includes("EXAME")) return true;
  if (n.includes("DATA DE IMPRESSAO")) return true;
  if (n.includes("USUARIO")) return true;
  if (n.includes("CODIGO") && n.includes("PACIENTE")) return true;

  return false;
}

function encontrarInicioExames(tokens) {
  for (let i = 0; i < tokens.length; i++) {
    if (ehTokenExame(tokens[i])) return i;
  }

  return -1;
}

// ======================================================
// 5. DADOS BASE
// ======================================================

const posto = extrairPosto(nomeArquivo, textoOCR);
const dataPadrao = extrairData(nomeArquivo, textoOCR);

// ======================================================
// 6. PROCESSA LINHAS
// ======================================================

const linhas = textoOCR
  .split(/\n+/)
  .map(l => limpar(l))
  .filter(Boolean);

const pacientes = [];
const chavesUsadas = new Set();

function adicionarPaciente({ data, codigo, paciente, exames }) {
  const pacienteLimpo = limpar(paciente).toUpperCase();
  const codigoLimpo = limpar(codigo);
  const dataLimpa = limpar(data || dataPadrao);
  const examesLimpos = [...new Set((exames || []).map(normalizarExame).filter(Boolean))];

  if (!codigoLimpo || !ehCodigo(codigoLimpo)) return;
  if (!pacienteLimpo || !ehNomePaciente(pacienteLimpo)) return;
  if (examesLimpos.length === 0) return;

  const chave = `${codigoLimpo}|${pacienteLimpo}|${examesLimpos.join(",")}`;

  if (chavesUsadas.has(chave)) return;
  chavesUsadas.add(chave);

  pacientes.push({
    data: dataLimpa,
    codigo: codigoLimpo,
    PACIENTE: pacienteLimpo,
    EXAMES: examesLimpos
  });
}

// ======================================================
// 6.1 PRIMEIRA TENTATIVA: LINHAS COM PIPE
// ======================================================

for (const linha of linhas) {
  if (!linha.includes("|")) continue;
  if (linhaIgnorada(linha)) continue;

  let cols = linha.split("|").map(c => limpar(c));

  if (cols[0] === "") cols.shift();
  if (cols[cols.length - 1] === "") cols.pop();

  if (cols.length < 4) continue;

  let dataLinha = "";
  let codigo = "";
  let paciente = "";
  let examesBruto = "";

  if (ehDataBR(cols[0]) && ehCodigo(cols[1])) {
    dataLinha = cols[0];
    codigo = cols[1];
    paciente = cols[2];
    examesBruto = cols.slice(3).join(" ");
  } else if (ehCodigo(cols[0])) {
    dataLinha = dataPadrao;
    codigo = cols[0];
    paciente = cols[1];
    examesBruto = cols.slice(2).join(" ");
  } else {
    continue;
  }

  adicionarPaciente({
    data: dataLinha,
    codigo,
    paciente,
    exames: separarExames(examesBruto)
  });
}

// ======================================================
// 6.2 SEGUNDA TENTATIVA: TEXTO SOLTO SEM PIPE
// ======================================================

for (const linhaOriginal of linhas) {
  if (linhaIgnorada(linhaOriginal)) continue;

  let linha = limpar(linhaOriginal)
    .replace(/[|]/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  let m = linha.match(/^(\d{2}\/\d{2}\/\d{4})\s+(\d{5,})\s+(.+)$/);

  let dataLinha = dataPadrao;
  let codigo = "";
  let restante = "";

  if (m) {
    dataLinha = m[1];
    codigo = m[2];
    restante = m[3];
  } else {
    m = linha.match(/^(\d{5,})\s+(.+)$/);

    if (!m) continue;

    codigo = m[1];
    restante = m[2];
  }

  const tokens = restante.split(/\s+/).map(t => limpar(t)).filter(Boolean);
  const idxExame = encontrarInicioExames(tokens);

  if (idxExame <= 0) continue;

  const paciente = tokens.slice(0, idxExame).join(" ");
  const examesBruto = tokens.slice(idxExame).join(" ");

  adicionarPaciente({
    data: dataLinha,
    codigo,
    paciente,
    exames: separarExames(examesBruto)
  });
}

// ======================================================
// 7. RETORNO FINAL
// ======================================================

if (pacientes.length === 0) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum paciente foi extraído do OCR.",
        posto,
        data: dataPadrao,
        nomeArquivo,
        debug: {
          totalLinhas: linhas.length,
          linhasComPipe: linhas.filter(l => l.includes("|")).length,
          primeirasLinhas: linhas.slice(0, 20),
          textoOCRInicio: textoOCR.slice(0, 1500)
        }
      }
    }
  ];
}

return pacientes.map((p, index) => ({
  json: {
    sucesso: true,
    categoria: "(+)COMPUTADOR DO POSTO",
    PACIENTE: p.PACIENTE,
    EXAMES: p.EXAMES,
    EXAMES_TEXTO: p.EXAMES.join(", "),
    QTD_EXAMES: p.EXAMES.length,
    VALOR: 0,
    posto,
    data: p.data || dataPadrao,
    codigo: p.codigo,
    _idx: index + 1,
    _totalPacientes: pacientes.length
  }
}));

// ======================================================
// COMPARA RECIBO x COMPUTADOR DO POSTO POR PACIENTE + EXAMES
// ✅ Input1 = RECIBO DE PAGAMENTO AO MEDICO
// ✅ Input2 = (+)COMPUTADOR DO POSTO / Code in JavaScript6
// ✅ NÃO remove recibo quando codigo/codIntegracao é igual ao computador
// ✅ Remove duplicados antes de comparar
// ✅ Compara paciente + exames normalizados em siglas
// ✅ Retorna PACIENTE_INPUT2 mesmo quando dá MATCH
// ======================================================

function normalizarTexto(valor) {
  return String(valor || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function limpar(valor) {
  return String(valor ?? "")
    .replace(/\u00A0/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function palavrasDoNome(nome) {
  return normalizarTexto(nome)
    .split(" ")
    .filter(Boolean);
}

function contarPalavrasIguais(nome1, nome2) {
  const palavras1 = new Set(palavrasDoNome(nome1));
  const palavras2 = new Set(palavrasDoNome(nome2));

  let iguais = 0;

  for (const palavra of palavras1) {
    if (palavras2.has(palavra)) iguais++;
  }

  return iguais;
}

function tresPrimeirasPalavrasIguaisNaSequencia(nome1, nome2) {
  const palavras1 = palavrasDoNome(nome1);
  const palavras2 = palavrasDoNome(nome2);

  if (palavras1.length < 3 || palavras2.length < 3) return false;

  return palavras1.slice(0, 3).join(" ") === palavras2.slice(0, 3).join(" ");
}

function garantirArray(valor) {
  if (!valor) return [];

  if (Array.isArray(valor)) {
    return valor
      .map(v => limpar(v))
      .filter(Boolean);
  }

  if (typeof valor === "string") {
    return valor
      .split(/,|;|\n/)
      .map(v => limpar(v))
      .filter(Boolean);
  }

  return [limpar(valor)].filter(Boolean);
}

// ======================================================
// NORMALIZA EXAMES PARA SIGLAS
// ======================================================

function normalizarExameParaSigla(exame) {
  const original = limpar(exame);
  const n = normalizarTexto(original);

  if (!n) return "";

  const siglasConhecidas = [
    "25OHD",
    "AUR",
    "B12",
    "CA",
    "CRE",
    "CTF",
    "CTFT",
    "GLIS",
    "HB1AC",
    "HBA1C",
    "HP",
    "IONO",
    "SU",
    "TRI",
    "TSH",
    "URE",
    "COAGU",
    "HEMO",
    "TPAE",
    "TTPA",
    "K",
    "FOSFO",
    "ALBUM",
    "NA",
    "MG",
    "PAPA",
    "AHCV",
    "HBSAG",
    "HIV",
    "T4L",
    "TGO",
    "TGP",
    "VDRL",
    "BHCG",
    "BETA",
    "HCG"
  ];

  if (n === "HBA1C") return "HB1AC";
  if (n === "GLI") return "GLIS";
  if (n === "BETA HCG") return "BHCG";
  if (n === "HCG") return "BHCG";
  if (n === "BETA") return "BHCG";

  if (siglasConhecidas.includes(n)) {
    return n;
  }

  if (
    n.includes("URINALISE") ||
    n.includes("URIANALISE") ||
    n.includes("SUMARIO DE URINA") ||
    n === "SU"
  ) {
    return "SU";
  }

  if (
    n.includes("BETA HCG") ||
    n.includes("TESTE DE GRAVIDEZ") ||
    n.includes("BHCG")
  ) {
    return "BHCG";
  }

  if (
    n.includes("COAGULOGRAMA") ||
    n.includes("TSTC") ||
    n.includes("PLAQ") ||
    n.includes("INR")
  ) {
    return "COAGU";
  }

  if (
    n.includes("GLICOSE") ||
    n === "GLI" ||
    n === "GLIS"
  ) {
    return "GLIS";
  }

  if (n.includes("UREIA") || n === "URE") {
    return "URE";
  }

  if (n.includes("HEMOGRAMA") || n === "HEMO") {
    return "HEMO";
  }

  if (n.includes("CREATININA") || n === "CRE") {
    return "CRE";
  }

  if (
    n.includes("TEMPO DE ATIVIDADE DE PROTROMBINA") ||
    n.includes("TPAE")
  ) {
    return "TPAE";
  }

  if (n.includes("POTASSIO") || n === "K") {
    return "K";
  }

  if (n.includes("FOSFORO") || n === "FOSFO") {
    return "FOSFO";
  }

  if (n.includes("ALBUMINA") || n === "ALBUM") {
    return "ALBUM";
  }

  if (
    n.includes("TEMPO DE TROMBOPLASTINA") ||
    n.includes("TTPA") ||
    n.includes("TTP")
  ) {
    return "TTPA";
  }

  if (n.includes("SODIO") || n === "NA") {
    return "NA";
  }

  if (
    n.includes("HEMOGLOBINA GLICADA") ||
    n.includes("HB1AC") ||
    n.includes("HBA1C")
  ) {
    return "HB1AC";
  }

  if (n.includes("MAGNESIO") || n === "MG") {
    return "MG";
  }

  if (
    n.includes("PAPANICOLAU") ||
    n.includes("CITOLOGIA") ||
    n === "PAPA"
  ) {
    return "PAPA";
  }

  if (
    n.includes("ANTI HCV") ||
    n.includes("ANTI-HCV") ||
    n.includes("AHCV")
  ) {
    return "AHCV";
  }

  if (
    n.includes("HBSAG") ||
    n.includes("HEPATITE B")
  ) {
    return "HBSAG";
  }

  if (n.includes("HIV")) {
    return "HIV";
  }

  if (
    n.includes("T4 LIVRE") ||
    n.includes("T4L")
  ) {
    return "T4L";
  }

  if (
    n.includes("TRANSAMINASE OXALACETICA") ||
    n.includes("TGO")
  ) {
    return "TGO";
  }

  if (
    n.includes("TRANSAMINASE PIRUVICA") ||
    n.includes("TGP")
  ) {
    return "TGP";
  }

  if (
    n.includes("VDRL") ||
    n.includes("TESTE LUETICO")
  ) {
    return "VDRL";
  }

  return n;
}

function normalizarListaExamesParaSiglas(exames) {
  return garantirArray(exames)
    .map(normalizarExameParaSigla)
    .filter(Boolean);
}

function ordenarExames(exames) {
  return [...new Set(exames)].sort((a, b) => a.localeCompare(b));
}

function compararExames(exames1, exames2) {
  const examesInput1 = ordenarExames(normalizarListaExamesParaSiglas(exames1));
  const examesInput2 = ordenarExames(normalizarListaExamesParaSiglas(exames2));

  const setInput1 = new Set(examesInput1);
  const setInput2 = new Set(examesInput2);

  const examesFaltando = examesInput1.filter(exame => !setInput2.has(exame));
  const examesExtras = examesInput2.filter(exame => !setInput1.has(exame));

  const matchExames =
    examesFaltando.length === 0 &&
    examesExtras.length === 0 &&
    examesInput1.length === examesInput2.length;

  return {
    examesInput1,
    examesInput2,
    examesFaltando,
    examesExtras,
    matchExames
  };
}

