function deduplicarItens(lista) {
  const vistos = new Set();

  return lista.filter(item => {
    const categoria = normalizarTexto(item.categoria);
    const paciente = normalizarTexto(item.PACIENTE);
    const codigo = String(item.codigo || item.codIntegracao || item.codAtend || item.atendimento || "");
    const exames = ordenarExames(normalizarListaExamesParaSiglas(item.EXAMES)).join("|");

    const chave = `${categoria}__${codigo}__${paciente}__${exames}`;

    if (vistos.has(chave)) {
      return false;
    }

    vistos.add(chave);
    return true;
  });
}

function ehComputadorDoPosto(item) {
  const categoria = normalizarTexto(item.categoria);

  return Boolean(
    item.PACIENTE &&
    Array.isArray(item.EXAMES) &&
    categoria.includes("COMPUTADOR DO POSTO")
  );
}

function ehReciboMedico(item) {
  const categoria = normalizarTexto(item.categoria);

  return Boolean(
    item.PACIENTE &&
    Array.isArray(item.EXAMES) &&
    categoria.includes("RECIBO DE PAGAMENTO AO MEDICO")
  );
}

