let input2Direto = [];

try {
  input2Direto = $("Code in JavaScript6").all().map(i => i.json);
} catch (e) {
  input2Direto = [];
}

// ======================================================
// 3. SEPARA INPUT1 E INPUT2
// ======================================================

let input2 = [];

if (input2Direto.length > 0) {
  input2 = input2Direto.filter(i =>
