    Array.isArray(i.EXAMES) &&
    normalizarTexto(i.categoria).includes("COMPUTADOR DO POSTO")
  );
} else {
  input2 = todos.filter(ehComputadorDoPosto);
}

let input1 = todos.filter(ehReciboMedico);

// Segurança: não deixa item do computador entrar como recibo.
// IMPORTANTE: não remove pelo código, porque o mesmo código pode existir nos dois lados.
input1 = input1.filter(item1 => {
  const cat1 = normalizarTexto(item1.categoria);
  return !cat1.includes("COMPUTADOR DO POSTO");
});

// Fallback: se não achou recibo pela categoria, pega tudo que não for computador
if (input1.length === 0) {
  input1 = todos.filter(item => {
    if (!item.PACIENTE || !Array.isArray(item.EXAMES)) return false;

    const catItem = normalizarTexto(item.categoria);

    if (catItem.includes("COMPUTADOR DO POSTO")) return false;

    return true;
  });
}

// ======================================================
// 3.1 REMOVE DUPLICADOS ANTES DA COMPARAÇÃO
// ======================================================

const totalInput1AntesDeduplicar = input1.length;
const totalInput2AntesDeduplicar = input2.length;

input1 = deduplicarItens(input1);
input2 = deduplicarItens(input2);

const totalInput1DepoisDeduplicar = input1.length;
const totalInput2DepoisDeduplicar = input2.length;

// ======================================================
// 4. DADOS GERAIS
// ======================================================

const posto =
  input2[0]?.posto ||
