const data =
  input1[0]?.data ||
  input2[0]?.data ||
  "";

// ======================================================
// 5. COMPARA INPUT1 CONTRA INPUT2
// ======================================================

const resultado = [];
const indicesInput2Usados = new Set();

for (const item1 of input1) {
  const pacienteInput1 = item1.PACIENTE || "";
  const examesInput1Original = garantirArray(item1.EXAMES);

  let melhorMatch = null;
  let melhorIndiceInput2 = -1;
  let maiorQtdPalavrasIguais = 0;
  let melhorComparacaoExames = null;

  // ======================================================
  // 5.1 Primeiro tenta paciente compatível + exames iguais
  // ======================================================

  for (let idx = 0; idx < input2.length; idx++) {
    if (indicesInput2Usados.has(idx)) continue;

    const item2 = input2[idx];
    const pacienteInput2 = item2.PACIENTE || "";

    const nomeCompletoIgual =
      normalizarTexto(pacienteInput1) === normalizarTexto(pacienteInput2);

    const match3Palavras =
      tresPrimeirasPalavrasIguaisNaSequencia(pacienteInput1, pacienteInput2);

    const matchPaciente = nomeCompletoIgual || match3Palavras;

    if (!matchPaciente) continue;

    const comparacaoExames = compararExames(item1.EXAMES, item2.EXAMES);

    if (comparacaoExames.matchExames) {
      melhorMatch = item2;
      melhorIndiceInput2 = idx;
      melhorComparacaoExames = comparacaoExames;
      maiorQtdPalavrasIguais = contarPalavrasIguais(pacienteInput1, pacienteInput2);
      break;
    }
  }

  // ======================================================
  // 5.2 Se não achou exames iguais, tenta achar só paciente
  // ======================================================

  if (!melhorMatch) {
    for (let idx = 0; idx < input2.length; idx++) {
      if (indicesInput2Usados.has(idx)) continue;

      const item2 = input2[idx];
      const pacienteInput2 = item2.PACIENTE || "";

      const nomeCompletoIgual =
        normalizarTexto(pacienteInput1) === normalizarTexto(pacienteInput2);

      const match3Palavras =
        tresPrimeirasPalavrasIguaisNaSequencia(pacienteInput1, pacienteInput2);

      const matchPaciente = nomeCompletoIgual || match3Palavras;

      if (!matchPaciente) continue;

      const qtdPalavrasIguais = contarPalavrasIguais(pacienteInput1, pacienteInput2);

      if (qtdPalavrasIguais > maiorQtdPalavrasIguais) {
        melhorMatch = item2;
        melhorIndiceInput2 = idx;
        maiorQtdPalavrasIguais = qtdPalavrasIguais;
        melhorComparacaoExames = compararExames(item1.EXAMES, item2.EXAMES);
      }
    }
  }

  const pacienteInput2Encontrado = melhorMatch?.PACIENTE || "";

  const nomeCompletoIgual =
    melhorMatch
      ? normalizarTexto(pacienteInput1) === normalizarTexto(pacienteInput2Encontrado)
      : false;

  const match3Palavras =
    melhorMatch
      ? tresPrimeirasPalavrasIguaisNaSequencia(pacienteInput1, pacienteInput2Encontrado)
      : false;

  const matchPaciente = Boolean(
    melhorMatch && (nomeCompletoIgual || match3Palavras)
  );

  if (!melhorComparacaoExames) {
    melhorComparacaoExames = compararExames(item1.EXAMES, melhorMatch?.EXAMES || []);
  }

  const matchExames =
    matchPaciente && melhorComparacaoExames.matchExames;

  const matchCompleto =
    matchPaciente && matchExames;

  if (matchPaciente && melhorIndiceInput2 >= 0) {
    indicesInput2Usados.add(melhorIndiceInput2);
  }

  resultado.push({
    json: {
      origemResultado: "RECIBO_COMPARADO_COM_COMPUTADOR",

      tipoResultado: matchCompleto
        ? "MATCH_COMPLETO"
        : matchPaciente
          ? "PACIENTE_MATCH_EXAMES_DIVERGENTES"
          : "RECIBO_SEM_MATCH_NO_COMPUTADOR",

      posto,
      data,

      PACIENTE_INPUT1: pacienteInput1,
      PACIENTE_INPUT2: pacienteInput2Encontrado,

      codigoInput1: item1.codigo || item1.codIntegracao || item1.codAtend || item1.atendimento || "",
      codigoInput2: melhorMatch?.codigo || melhorMatch?.codIntegracao || melhorMatch?.codAtend || melhorMatch?.atendimento || "",

      matchPaciente,
      nomeCompletoIgual,
      matchPor3Palavras: !nomeCompletoIgual && match3Palavras,

      palavrasIguaisPaciente: maiorQtdPalavrasIguais,

      primeiras3PalavrasInput1:
        palavrasDoNome(pacienteInput1).slice(0, 3),

      primeiras3PalavrasInput2:
        pacienteInput2Encontrado
          ? palavrasDoNome(pacienteInput2Encontrado).slice(0, 3)
          : [],

      matchExames,
      matchCompleto,

      quantidadeExamesInput1:
        melhorComparacaoExames.examesInput1.length,

      quantidadeExamesInput2:
        melhorComparacaoExames.examesInput2.length,

      examesInput1:
        melhorComparacaoExames.examesInput1,

      examesInput2:
        melhorComparacaoExames.examesInput2,

      examesFaltandoNoInput2:
        matchPaciente
          ? melhorComparacaoExames.examesFaltando
          : melhorComparacaoExames.examesInput1,

      examesExtrasNoInput2:
        matchPaciente
          ? melhorComparacaoExames.examesExtras
          : [],

      examesInput1Original,
      examesInput2Original: garantirArray(melhorMatch?.EXAMES || []),

      erro: !matchCompleto,

      mensagem:
        matchCompleto
