          : matchPaciente
            ? "Paciente encontrado, mas há divergência entre os exames"
            : "Paciente do recibo não encontrado no computador",

      debugDeduplicacao: {
        totalInput1AntesDeduplicar,
        totalInput1DepoisDeduplicar,
        totalInput2AntesDeduplicar,
        totalInput2DepoisDeduplicar
      }
    }
  });
}

// ======================================================
