const todos = $input.all();

function normalizarTexto(txt) {
  return String(txt || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^A-Z0-9]/g, "")
    .trim();
}

function normalizarNome(txt) {
  return String(txt || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^A-Z0-9\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

const pacientes = todos.filter(item => item.json.PACIENTE);

const tabela = todos.filter(item =>
  item.json.NOME_EXAME &&
  item.json.SIGLA
);

// ======================================================
// MAPAS SEPARADOS
// 1. mapaSiglas: só aceita match exato
// 2. mapaNomes: pode aceitar nome completo / nome sem parênteses
// ======================================================

const mapaSiglas = new Map();
const mapaNomes = new Map();

for (const item of tabela) {
  const sigla = String(item.json.NOME_EXAME || "")
    .trim()
    .toUpperCase();

  const nomeCompleto = String(item.json.SIGLA || "")
    .trim();

  if (!sigla || !nomeCompleto) continue;

  // SIGLA: somente match exato
  mapaSiglas.set(
    normalizarTexto(sigla),
    sigla
  );

  // NOME COMPLETO: match exato pelo nome
  mapaNomes.set(
    normalizarNome(nomeCompleto),
    sigla
  );

  // NOME ANTES DOS PARÊNTESES
  const nomeAntesParenteses = nomeCompleto
    .split("(")[0]
    .trim();

  if (nomeAntesParenteses) {
    mapaNomes.set(
      normalizarNome(nomeAntesParenteses),
      sigla
    );
  }
}

function converterExame(exame) {
  const original = String(exame || "").trim();

  if (!original) {
    return {
      encontrado: false,
      original
    };
  }

  const chaveSigla = normalizarTexto(original);
  const chaveNome = normalizarNome(original);

  // ======================================================
  // 1. MATCH EXATO POR SIGLA
  // Exemplo:
  // GLI só vira GLI
  // A1GLI só vira A1GLI
  // Nunca GLI vira A1GLI
  // ======================================================

  if (mapaSiglas.has(chaveSigla)) {
    return {
      encontrado: true,
      sigla: mapaSiglas.get(chaveSigla)
    };
  }

  // ======================================================
  // 2. REMOVE PARÊNTESES E TENTA MATCH EXATO
  // ======================================================

  const semParenteses = original
    .replace(/\([^)]*\)/g, "")
    .trim();

  const chaveSemParentesesSigla = normalizarTexto(semParenteses);
  const chaveSemParentesesNome = normalizarNome(semParenteses);

  if (mapaSiglas.has(chaveSemParentesesSigla)) {
    return {
      encontrado: true,
      sigla: mapaSiglas.get(chaveSemParentesesSigla)
    };
  }

  if (mapaNomes.has(chaveNome)) {
    return {
      encontrado: true,
      sigla: mapaNomes.get(chaveNome)
    };
  }

  if (mapaNomes.has(chaveSemParentesesNome)) {
    return {
      encontrado: true,
      sigla: mapaNomes.get(chaveSemParentesesNome)
    };
  }

  // ======================================================
  // 3. MATCH PARCIAL SEGURO
  // Só aplica para nomes longos, nunca para siglas curtas.
  // Evita erro tipo GLI virar A1GLI.
  // ======================================================

  if (chaveNome.length >= 8) {
    for (const [nomeNormalizado, sigla] of mapaNomes.entries()) {
      if (
        nomeNormalizado.length >= 8 &&
        (
          chaveNome.includes(nomeNormalizado) ||
          nomeNormalizado.includes(chaveNome)
        )
      ) {
        return {
          encontrado: true,
          sigla
        };
      }
    }
  }

  // ======================================================
  // 4. NÃO ENCONTRADO
  // Mantém o exame original
  // ======================================================

  return {
    encontrado: false,
    original
  };
}

const resultado = pacientes.map((item, index) => {
  const json = item.json;

  const examesOriginais = Array.isArray(json.EXAMES)
    ? json.EXAMES
    : String(json.EXAMES_TEXTO || "")
        .split(",")
        .map(e => e.trim())
        .filter(Boolean);

  const examesNormalizados = [];
  const examesNaoEncontrados = [];

  for (const exame of examesOriginais) {
    const convertido = converterExame(exame);

    if (convertido.encontrado) {
      examesNormalizados.push(convertido.sigla);
    } else {
      examesNaoEncontrados.push(convertido.original);
      examesNormalizados.push(
        String(convertido.original || "").toUpperCase()
      );
    }
  }

  return {
    json: {
      ...json,

      EXAMES: examesNormalizados,

      EXAMES_TEXTO: examesNormalizados.join(", "),

      EXAMES_NAO_ENCONTRADOS: examesNaoEncontrados,

      QTD_EXAMES: examesNormalizados.length,

      _idx: index + 1,

      _totalPacientes: pacientes.length
    }
  };
});

return resultado;

// ======================================================
// EXTRATOR OCR - PROTOCOLO DE ENVIO AO LABORATÓRIO
// ✅ Extrai pacientes da tabela markdown do OCR
// ✅ Retorna 1 item por paciente
// ✅ Remove valores entre colchetes dos exames
// ✅ Posto vem do nome do arquivo ou do texto: P12 / P: 12
// ✅ Data vem prioritariamente de: Data do Envio: DD/MM/AAAA
// ======================================================

const input = $input.first().json;

// ======================================================
// 1. PEGA NOME DO ARQUIVO
// ======================================================

let nomeArquivo = "";

try {
  nomeArquivo = String($("ENVIO").first().json.name || "");
} catch (e) {
  nomeArquivo = String(input.name || input.fileName || "");
}

// ======================================================
// 2. PEGA TEXTO OCR
// ======================================================

const textoOCR = String(
  input.extractedText ||
  input.text ||
  input.markdown ||
  input.conteudo ||
  input.content ||
  (Array.isArray(input.pages)
    ? input.pages.map(p => p.markdown || p.text || "").join("\n")
    : "") ||
  ""
);

if (!textoOCR.trim()) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum texto OCR encontrado.",
        nomeArquivo
      }
    }
  ];
}

// ======================================================
// 3. FUNÇÕES AUXILIARES
// ======================================================

function limpar(valor) {
  return String(valor ?? "")
    .replace(/\u00A0/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizar(valor) {
  return limpar(valor)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase();
}

function extrairPosto(nome, texto) {
  const fonte = `${nome || ""}\n${texto || ""}`;

  // Nome do arquivo: P12, P 12, P012
  let m = fonte.match(/\bP\s*0*(\d{1,5})\b/i);
  if (m) return m[1];

  // Texto: P: 12
  m = fonte.match(/\bP\s*:\s*0*(\d{1,5})\b/i);
  if (m) return m[1];

  // Texto: Posto 12
  m = fonte.match(/\bPOSTO\s*0*(\d{1,5})\b/i);
  if (m) return m[1];

  return "";
}

function extrairData(nome, texto) {
  const fonte = `${nome || ""}\n${texto || ""}`;

  // PRIORIDADE 1:
  // Data do Envio: 25/05/2026
  let m = fonte.match(/Data\s+do\s+Envio\s*:\s*(\d{2})\/(\d{2})\/(\d{4})/i);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  // PRIORIDADE 2:
  // Data do Envio: 25.05.2026
  m = fonte.match(/Data\s+do\s+Envio\s*:\s*(\d{2})\.(\d{2})\.(\d{4})/i);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  // PRIORIDADE 3:
  // Data do Envio: 25-05-2026
  m = fonte.match(/Data\s+do\s+Envio\s*:\s*(\d{2})-(\d{2})-(\d{4})/i);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  // Fallback 1:
  // Qualquer data DD/MM/AAAA
  m = fonte.match(/\b(\d{2})\/(\d{2})\/(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  // Fallback 2:
  // Qualquer data DD.MM.AAAA
  m = fonte.match(/\b(\d{2})\.(\d{2})\.(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  // Fallback 3:
  // Qualquer data DD-MM-AAAA
  m = fonte.match(/\b(\d{2})-(\d{2})-(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  return "";
}

function removerValoresColchetes(texto) {
  return String(texto || "")
    .replace(/\[[^\]]*]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function separarExames(textoExames, posto) {
  let texto = removerValoresColchetes(textoExames);

  if (!texto) return [];

  // Regra específica para P137
  if (String(posto) === "137") {
    texto = texto.replace(/\bGLICOSE\s+JEJUM\b/gi, "GLI");
  }

  const exames = [];
  let atual = "";
  let nivelParenteses = 0;

  for (let i = 0; i < texto.length; i++) {
    const char = texto[i];

    if (char === "(") {
      nivelParenteses++;
      atual += char;
      continue;
    }

    if (char === ")") {
      nivelParenteses = Math.max(0, nivelParenteses - 1);
      atual += char;
      continue;
    }

    // Se tiver vírgula fora de parênteses, separa exame
    if (char === "," && nivelParenteses === 0) {
      const exame = limpar(atual);
      if (exame) exames.push(exame);
      atual = "";
      continue;
    }

    atual += char;
  }

  const ultimo = limpar(atual);
  if (ultimo) exames.push(ultimo);

  return exames
    .map(e => limpar(e))
    .filter(e => e)
    .filter(e => !/^\d+([.,]\d+)?$/.test(e));
}

function ehLinhaPaciente(cols) {
  if (cols.length < 5) return false;

  const codIntegracao = limpar(cols[0]);
  const codAtend = limpar(cols[1]);
  const paciente = limpar(cols[2]);
  const exames = limpar(cols[3]);

  if (!/^\d{6,}$/.test(codIntegracao)) return false;
  if (!/^\d{4,}$/.test(codAtend)) return false;
  if (!paciente || paciente.length < 5) return false;
  if (/\d/.test(paciente)) return false;
  if (!exames) return false;

  const nPaciente = normalizar(paciente);

  const bloqueados = [
    "PACIENTE",
    "COD INTEGRACAO",
    "COD INTEGRAÇÃO",
    "COD ATEND",
    "EXAMES",
    "VALOR",
    "DESC CLI",
    "DESC LAB",
    "SALDO LAB",
    "PROTOCOLO",
    "LABORATORIO",
    "LABORATÓRIO"
  ];

  if (bloqueados.some(p => nPaciente.includes(normalizar(p)))) return false;

  return true;
}

// ======================================================
// 4. DADOS BASE
// ======================================================

const posto = extrairPosto(nomeArquivo, textoOCR);
const data = extrairData(nomeArquivo, textoOCR);

// ======================================================
// 5. EXTRAI LINHAS DA TABELA
// ======================================================

const linhas = textoOCR
  .split(/\r?\n/)
  .map(l => limpar(l))
  .filter(Boolean);

const pacientes = [];

for (const linha of linhas) {
  if (!linha.includes("|")) continue;

  let cols = linha.split("|").map(c => limpar(c));

  // Remove primeira coluna vazia se a linha começa com |
  if (cols[0] === "") cols.shift();

  // Remove última coluna vazia se a linha termina com |
  if (cols[cols.length - 1] === "") cols.pop();

  if (!ehLinhaPaciente(cols)) continue;

  const codIntegracao = limpar(cols[0]);
  const codAtend = limpar(cols[1]);
  const paciente = normalizar(cols[2]);
  const examesBruto = limpar(cols[3]);
  const valorLinha = limpar(cols[4]);

  const exames = separarExames(examesBruto, posto);

  if (exames.length === 0) continue;

  pacientes.push({
    codIntegracao,
    codAtend,
    PACIENTE: paciente,
    EXAMES: exames,
    valorLinha
  });
}

// ======================================================
// 6. RETORNO FINAL
// ======================================================

if (pacientes.length === 0) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum paciente foi extraído do OCR.",
        posto,
        data,
        nomeArquivo,
        debug: {
          totalLinhas: linhas.length,
          linhasComPipe: linhas.filter(l => l.includes("|")).length,
          primeirasLinhas: linhas.slice(0, 15),
          primeirasLinhasComPipe: linhas.filter(l => l.includes("|")).slice(0, 10)
        }
      }
    }
  ];
}

const resultado = pacientes.map((p, index) => ({
  json: {
    sucesso: true,
    categoria: "RECIBO DE PAGAMENTO AO MEDICO",
    PACIENTE: p.PACIENTE,
    EXAMES: p.EXAMES,
    EXAMES_TEXTO: p.EXAMES.join(", "),
    QTD_EXAMES: p.EXAMES.length,
    VALOR: 0,
    posto,
    data,
    codIntegracao: p.codIntegracao,
    codAtend: p.codAtend,
    valorLinha: p.valorLinha,
    _idx: index + 1,
    _totalPacientes: pacientes.length
  }
}));

return resultado;

// ======================================================
// COMPARA RECIBO x COMPUTADOR DO POSTO POR PACIENTE + EXAMES
// ✅ Usa o input atual do Merge
// ✅ Input1 = RECIBO DE PAGAMENTO AO MÉDICO
// ✅ Input2 = (+)COMPUTADOR DO POSTO
// ✅ Normaliza exames para SIGLAS antes de comparar
// ✅ Retorna examesInput1 e examesInput2 em formato de sigla
// ======================================================

function normalizarTexto(valor) {
  return String(valor || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function limpar(valor) {
  return String(valor ?? "")
    .replace(/\u00A0/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function palavrasDoNome(nome) {
  return normalizarTexto(nome)
    .split(" ")
    .filter(Boolean);
}

function contarPalavrasIguais(nome1, nome2) {
  const palavras1 = new Set(palavrasDoNome(nome1));
  const palavras2 = new Set(palavrasDoNome(nome2));

  let iguais = 0;

  for (const palavra of palavras1) {
    if (palavras2.has(palavra)) iguais++;
  }

  return iguais;
}

function tresPrimeirasPalavrasIguaisNaSequencia(nome1, nome2) {
  const palavras1 = palavrasDoNome(nome1);
  const palavras2 = palavrasDoNome(nome2);

  if (palavras1.length < 3 || palavras2.length < 3) return false;

  return palavras1.slice(0, 3).join(" ") === palavras2.slice(0, 3).join(" ");
}

function garantirArray(valor) {
  if (!valor) return [];

  if (Array.isArray(valor)) {
    return valor
      .map(v => limpar(v))
      .filter(Boolean);
  }

  if (typeof valor === "string") {
    return valor
      .split(/,|;|\n/)
      .map(v => limpar(v))
      .filter(Boolean);
  }

  return [limpar(valor)].filter(Boolean);
}

// ======================================================
// MAPA DE EXAMES PARA SIGLAS
// Ajuste ou acrescente novas regras aqui quando necessário
// ======================================================

function normalizarExameParaSigla(exame) {
  const original = limpar(exame);
  const n = normalizarTexto(original);

  if (!n) return "";

  // Se já vier como sigla conhecida, mantém
  const siglasConhecidas = [
    "COAGU",
    "GLIS",
    "URE",
    "HEMO",
    "CRE",
    "TPAE",
    "K",
    "FOSFO",
    "ALBUM",
    "TTPA",
    "NA",
    "HB1AC",
    "MG",
    "PAPA"
  ];

  if (siglasConhecidas.includes(n)) {
    return n;
  }

  // COAGULOGRAMA
  if (
    n.includes("COAGULOGRAMA") ||
    n.includes("TSTC") ||
    n.includes("PLAQ") ||
    n.includes("P L ACO") ||
    n.includes("INR")
  ) {
    return "COAGU";
  }

  // GLICOSE
  if (
    n.includes("GLICOSE") ||
    n === "GLI" ||
    n === "GLIS"
  ) {
    return "GLIS";
  }

  // UREIA
  if (n.includes("UREIA") || n === "URE") {
    return "URE";
  }

  // HEMOGRAMA
  if (n.includes("HEMOGRAMA") || n === "HEMO") {
    return "HEMO";
  }

  // CREATININA
  if (n.includes("CREATININA") || n === "CRE") {
    return "CRE";
  }

  // TEMPO DE ATIVIDADE DE PROTROMBINA
  if (
    n.includes("TEMPO DE ATIVIDADE DE PROTROMBINA") ||
    n.includes("TPAE")
  ) {
    return "TPAE";
  }

  // POTÁSSIO
  if (n.includes("POTASSIO") || n === "K") {
    return "K";
  }

  // FÓSFORO
  if (n.includes("FOSFORO") || n === "FOSFO") {
    return "FOSFO";
  }

  // ALBUMINA
  if (n.includes("ALBUMINA") || n === "ALBUM") {
    return "ALBUM";
  }

  // TTPA
  if (
    n.includes("TEMPO DE TROMBOPLASTINA") ||
    n.includes("TTPA") ||
    n.includes("TTP")
  ) {
    return "TTPA";
  }

  // SÓDIO
  if (n.includes("SODIO") || n === "NA") {
    return "NA";
  }

  // HEMOGLOBINA GLICADA
  if (
    n.includes("HEMOGLOBINA GLICADA") ||
    n.includes("HB1AC") ||
    n.includes("HBA1C")
  ) {
    return "HB1AC";
  }

  // MAGNÉSIO
  if (n.includes("MAGNESIO") || n === "MG") {
    return "MG";
  }

  // PAPANICOLAU
  if (
    n.includes("PAPANICOLAU") ||
    n.includes("CITOLOGIA") ||
    n === "PAPA"
  ) {
    return "PAPA";
  }

  // Se não encontrar no mapa, retorna normalizado
  return n;
}

function normalizarListaExamesParaSiglas(exames) {
  return garantirArray(exames)
    .map(normalizarExameParaSigla)
    .filter(Boolean);
}

function ordenarExames(exames) {
  return [...exames].sort((a, b) => a.localeCompare(b));
}

function compararExames(exames1, exames2) {
  const examesInput1 = normalizarListaExamesParaSiglas(exames1);
  const examesInput2 = normalizarListaExamesParaSiglas(exames2);

  const examesInput1Ordenados = ordenarExames(examesInput1);
  const examesInput2Ordenados = ordenarExames(examesInput2);

  const setInput1 = new Set(examesInput1Ordenados);
  const setInput2 = new Set(examesInput2Ordenados);

  const examesFaltando = examesInput1Ordenados.filter(exame => !setInput2.has(exame));
  const examesExtras = examesInput2Ordenados.filter(exame => !setInput1.has(exame));

  const matchExames =
    examesFaltando.length === 0 &&
    examesExtras.length === 0 &&
    examesInput1Ordenados.length === examesInput2Ordenados.length;

  return {
    examesInput1: examesInput1Ordenados,
    examesInput2: examesInput2Ordenados,
    examesFaltando,
    examesExtras,
    matchExames
  };
}

// ======================================================
// 1. PEGA TODOS OS DADOS DO INPUT ATUAL
// ======================================================

const todos = $input.all().map(i => i.json);

// ======================================================
// 2. SEPARA INPUT1 E INPUT2 PELA CATEGORIA
// ======================================================

let input1 = todos.filter(i =>
  i.PACIENTE &&
  Array.isArray(i.EXAMES) &&
  normalizarTexto(i.categoria).includes("RECIBO DE PAGAMENTO AO MEDICO")
);

let input2 = todos.filter(i =>
  i.PACIENTE &&
  Array.isArray(i.EXAMES) &&
  normalizarTexto(i.categoria).includes("COMPUTADOR DO POSTO")
);

// Fallback caso as categorias venham diferentes
if (input1.length === 0) {
  input1 = todos.filter(i =>
    i.PACIENTE &&
    Array.isArray(i.EXAMES) &&
    i.medico &&
    i.numeroRecibo
  );
}

if (input2.length === 0) {
  input2 = todos.filter(i =>
    i.PACIENTE &&
    Array.isArray(i.EXAMES) &&
    i.codigo
  );
}

// ======================================================
// 3. DADOS GERAIS
// ======================================================

const posto =
  input2[0]?.posto ||
  input1[0]?.posto ||
  "";

const data =
  input1[0]?.data ||
  input2[0]?.data ||
  "";

// ======================================================
// 4. COMPARA INPUT1 CONTRA INPUT2
// ======================================================

const resultado = [];
const indicesInput2Usados = new Set();

for (const item1 of input1) {
  const pacienteInput1 = item1.PACIENTE || "";

  const examesInput1Original = garantirArray(item1.EXAMES);

  let melhorMatch = null;
  let melhorIndiceInput2 = -1;
  let maiorQtdPalavrasIguais = 0;
  let melhorComparacaoExames = null;

  // ======================================================
  // 4.1 Primeiro tenta paciente compatível + exames iguais
  // ======================================================

  for (let idx = 0; idx < input2.length; idx++) {
    if (indicesInput2Usados.has(idx)) continue;

    const item2 = input2[idx];
    const pacienteInput2 = item2.PACIENTE || "";

    const nomeCompletoIgual =
      normalizarTexto(pacienteInput1) === normalizarTexto(pacienteInput2);

    const match3Palavras =
      tresPrimeirasPalavrasIguaisNaSequencia(pacienteInput1, pacienteInput2);

    const matchPaciente = nomeCompletoIgual || match3Palavras;

    if (!matchPaciente) continue;

    const comparacaoExames = compararExames(item1.EXAMES, item2.EXAMES);

    if (comparacaoExames.matchExames) {
      melhorMatch = item2;
      melhorIndiceInput2 = idx;
      melhorComparacaoExames = comparacaoExames;
      maiorQtdPalavrasIguais = contarPalavrasIguais(pacienteInput1, pacienteInput2);
      break;
    }
  }

  // ======================================================
  // 4.2 Se não achou match completo, tenta achar só paciente
  // ======================================================

  if (!melhorMatch) {
    for (let idx = 0; idx < input2.length; idx++) {
      if (indicesInput2Usados.has(idx)) continue;

      const item2 = input2[idx];
      const pacienteInput2 = item2.PACIENTE || "";

      const nomeCompletoIgual =
        normalizarTexto(pacienteInput1) === normalizarTexto(pacienteInput2);

      const match3Palavras =
        tresPrimeirasPalavrasIguaisNaSequencia(pacienteInput1, pacienteInput2);

      const matchPaciente = nomeCompletoIgual || match3Palavras;

      if (!matchPaciente) continue;

      const qtdPalavrasIguais = contarPalavrasIguais(pacienteInput1, pacienteInput2);

      if (qtdPalavrasIguais > maiorQtdPalavrasIguais) {
        melhorMatch = item2;
        melhorIndiceInput2 = idx;
        maiorQtdPalavrasIguais = qtdPalavrasIguais;
        melhorComparacaoExames = compararExames(item1.EXAMES, item2.EXAMES);
      }
    }
  }

  const pacienteInput2Encontrado = melhorMatch?.PACIENTE || "";

  const nomeCompletoIgual =
    melhorMatch
      ? normalizarTexto(pacienteInput1) === normalizarTexto(pacienteInput2Encontrado)
      : false;

  const match3Palavras =
    melhorMatch
      ? tresPrimeirasPalavrasIguaisNaSequencia(pacienteInput1, pacienteInput2Encontrado)
      : false;

  const matchPaciente = Boolean(
    melhorMatch && (nomeCompletoIgual || match3Palavras)
  );

  if (!melhorComparacaoExames) {
    melhorComparacaoExames = compararExames(item1.EXAMES, melhorMatch?.EXAMES || []);
  }

  const matchExames =
    matchPaciente && melhorComparacaoExames.matchExames;

  const matchCompleto =
    matchPaciente && matchExames;

  if (matchPaciente && melhorIndiceInput2 >= 0) {
    indicesInput2Usados.add(melhorIndiceInput2);
  }

  resultado.push({
    json: {
      origemResultado: "RECIBO_COMPARADO_COM_COMPUTADOR",

      tipoResultado: matchCompleto
        ? "MATCH_COMPLETO"
        : matchPaciente
          ? "PACIENTE_MATCH_EXAMES_DIVERGENTES"
          : "RECIBO_SEM_MATCH_NO_COMPUTADOR",

      posto,
      data,

      PACIENTE_INPUT1: pacienteInput1,
      PACIENTE_INPUT2: pacienteInput2Encontrado,

      matchPaciente,

      nomeCompletoIgual,

      matchPor3Palavras:
        !nomeCompletoIgual && match3Palavras,

      palavrasIguaisPaciente:
        maiorQtdPalavrasIguais,

      primeiras3PalavrasInput1:
        palavrasDoNome(pacienteInput1).slice(0, 3),

      primeiras3PalavrasInput2:
        pacienteInput2Encontrado
          ? palavrasDoNome(pacienteInput2Encontrado).slice(0, 3)
          : [],

      matchExames,

      matchCompleto,

      quantidadeExamesInput1:
        melhorComparacaoExames.examesInput1.length,

      quantidadeExamesInput2:
        melhorComparacaoExames.examesInput2.length,

      // Agora retorna em SIGLAS
      examesInput1:
        melhorComparacaoExames.examesInput1,

      examesInput2:
        melhorComparacaoExames.examesInput2,

      examesFaltandoNoInput2:
        matchPaciente
          ? melhorComparacaoExames.examesFaltando
          : melhorComparacaoExames.examesInput1,

      examesExtrasNoInput2:
        matchPaciente
          ? melhorComparacaoExames.examesExtras
          : [],

      // Mantém o original só para debug, se precisar conferir
      examesInput1Original,

      erro:
        !matchCompleto,

      mensagem:
        matchCompleto
          ? "Paciente e exames estão iguais"
          : matchPaciente
            ? "Paciente encontrado, mas há divergência entre os exames"
            : "Paciente do recibo não encontrado no computador"
    }
  });
}

// ======================================================
// 5. RETORNA INPUT2 QUE NÃO TEVE CORRESPONDÊNCIA NO INPUT1
// ======================================================

for (let idx = 0; idx < input2.length; idx++) {
  if (indicesInput2Usados.has(idx)) continue;

  const item2 = input2[idx];

  const pacienteInput2 = item2.PACIENTE || "";
  const examesInput2 = normalizarListaExamesParaSiglas(item2.EXAMES);

  resultado.push({
    json: {
      origemResultado: "COMPUTADOR_SEM_MATCH_NO_RECIBO",

      tipoResultado: "COMPUTADOR_SEM_MATCH_NO_RECIBO",

      posto: item2.posto || posto,
      data: item2.data || data,

      PACIENTE_INPUT1: "",
      PACIENTE_INPUT2: pacienteInput2,

      matchPaciente: false,

      nomeCompletoIgual: false,

      matchPor3Palavras: false,

      palavrasIguaisPaciente: 0,

      primeiras3PalavrasInput1: [],

      primeiras3PalavrasInput2:
        palavrasDoNome(pacienteInput2).slice(0, 3),

      matchExames: false,

      matchCompleto: false,

      quantidadeExamesInput1: 0,

      quantidadeExamesInput2:
        examesInput2.length,

      examesInput1: [],

      examesInput2,

      examesFaltandoNoInput2: [],

      examesExtrasNoInput2:
        examesInput2,

      erro: true,

      mensagem:
        "Paciente existe no computador, mas não foi encontrado correspondente no recibo"
    }
  });
}

// ======================================================
// 6. RETORNO FINAL
// ======================================================

if (resultado.length === 0) {
  return [
    {
      json: {
        erro: true,
        mensagem: "Nenhum resultado encontrado na comparação.",
        totalInputAtual: todos.length,
        totalInput1Recibo: input1.length,
        totalInput2Computador: input2.length,
        posto,
        data,
        debugCategorias: todos.map(i => i.categoria || "")
      }
    }
  ];
}

return resultado;

// ======================================================
// EXTRATOR OCR - RELATÓRIO DE MOTOQUEIROS / LABOVIDA
// ✅ Retorna 1 item por paciente
// ✅ Usa SOMENTE exames da tabela dinâmica NOME_EXAME
// ✅ Sem examesFallback
// ✅ PACIENTE tem prioridade
// ✅ Captura vários pacientes mesmo quando o OCR vem em uma linha única
// ======================================================

const todosItens = $input.all();

// ======================================================
// 0. LOCALIZA ITEM OCR
// ======================================================

const itemOCR = todosItens.find(item => {
  const j = item.json || {};
  return (
    j.extractedText ||
    j.text ||
    j.markdown ||
    j.conteudo ||
    j.content ||
    Array.isArray(j.pages)
  );
});

if (!itemOCR) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum item com texto OCR foi encontrado no input do Merge.",
        totalItensRecebidos: todosItens.length
      }
    }
  ];
}

const input = itemOCR.json;

// ======================================================
// 1. FUNÇÕES BÁSICAS
// ======================================================

function limpar(valor) {
  return String(valor ?? "")
    .replace(/\u00A0/g, " ")
    .replace(/[ \t]+/g, " ")
    .trim();
}

function normalizar(valor) {
  return limpar(valor)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase();
}

// ======================================================
// 2. EXAMES CONHECIDOS - SOMENTE DO MERGE
// Campo esperado: NOME_EXAME
// ======================================================

const examesConhecidos = [
  ...new Set(
    todosItens
      .map(item => item.json || {})
      .map(j => j.NOME_EXAME)
      .filter(v => v !== undefined && v !== null && String(v).trim() !== "")
      .map(v => normalizar(v))
  )
];

const examesSet = new Set(examesConhecidos);

// ======================================================
// 3. NOME DO ARQUIVO
// ======================================================

let nomeArquivo = "";

try {
  nomeArquivo = String($("ENVIO").first().json.name || "");
} catch (e) {
  nomeArquivo = String(input.name || input.fileName || "");
}

// ======================================================
// 4. TEXTO OCR
// ======================================================

let textoOCR = String(
  input.extractedText ||
  input.text ||
  input.markdown ||
  input.conteudo ||
  input.content ||
  (Array.isArray(input.pages)
    ? input.pages.map(p => p.markdown || p.text || "").join("\n")
    : "") ||
  ""
);

// Corrige \n literal
textoOCR = textoOCR.replace(/\\n/g, "\n");

// Garante quebra antes de todo novo paciente
textoOCR = textoOCR.replace(
  /\s+(?=\d{2}\/\d{2}\/\d{4}\s+\d{4,}\s+)/g,
  "\n"
);

if (!textoOCR.trim()) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum texto OCR encontrado.",
        nomeArquivo
      }
    }
  ];
}

// ======================================================
// 5. FUNÇÕES AUXILIARES
// ======================================================

function extrairPosto(nomeArquivo, texto) {
  const fonte = `${nomeArquivo || ""}\n${texto || ""}`;

  let m = fonte.match(/\bP\s*0*(\d{1,5})\b/i);
  if (m) return m[1];

  m = fonte.match(/\bP\s*:\s*0*(\d{1,5})\b/i);
  if (m) return m[1];

  m = fonte.match(/\bPOSTO\s*0*(\d{1,5})\b/i);
  if (m) return m[1];

  // Exemplo: 7626213 -> posto 76
  m = fonte.match(/\b(\d{2,3})\d{5,}\b/);
  if (m) return String(Number(m[1]));

  return "";
}

function extrairData(nomeArquivo, texto) {
  const fonte = `${nomeArquivo || ""}\n${texto || ""}`;

  let m = fonte.match(/Data\s+do\s+Envio\s*:\s*(\d{2})\/(\d{2})\/(\d{4})/i);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  m = fonte.match(/\b(\d{2})\.(\d{2})\.(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  m = fonte.match(/\b(\d{2})\/(\d{2})\/(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  m = fonte.match(/\b(\d{2})-(\d{2})-(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  return "";
}

function removerColchetes(texto) {
  return String(texto || "")
    .replace(/\[[^\]]*]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function ehDataBR(valor) {
  return /^\d{2}\/\d{2}\/\d{4}$/.test(limpar(valor));
}

function ehCodigo(valor) {
  return /^\d{4,}$/.test(limpar(valor));
}

function ehNomePaciente(valor) {
  const texto = limpar(valor);
  const n = normalizar(texto);

  if (!texto) return false;
  if (texto.length < 5) return false;
  if (/\d/.test(texto)) return false;

  const bloqueados = [
    "LABOVIDA",
    "RELATORIO",
    "RELATÓRIO",
    "MOTOQUEIROS",
    "RESUMO",
    "PACIENTES",
    "EXAME",
    "EXAMES",
    "USUARIO",
    "USUÁRIO",
    "DATA DE IMPRESSAO",
    "DATA DE IMPRESSÃO"
  ];

  return !bloqueados.some(b => n.includes(normalizar(b)));
}

function corrigirExameOCR(exame) {
  const e = normalizar(exame);

  // Se existe na tabela, mantém exatamente como veio.
  if (examesSet.has(e)) return e;

  const mapa = {
    "GLICOSE": "GLIS"
  };

  const corrigido = mapa[e];

  if (corrigido && examesSet.has(corrigido)) {
    return corrigido;
  }

  return e;
}

function separarExames(textoExames, posto) {
  let texto = removerColchetes(textoExames);

  if (!texto) return [];

  if (String(posto) === "137") {
    texto = texto.replace(/\bGLICOSE\s+JEJUM\b/gi, "GLI");
  }

  return texto
    .split(/\s+/)
    .map(e => limpar(e))
    .filter(e => e)
    .map(e => corrigirExameOCR(e))
    .filter(e => !/^\d+([.,]\d+)?$/.test(e))
    .filter(e => examesSet.has(e));
}

function linhaIgnorada(linha) {
  const n = normalizar(linha);

  if (!n) return true;
  if (n.includes("---")) return true;
  if (n === "LABOVIDA") return true;
  if (n.includes("RELATORIO DE MOTOQUEIROS")) return true;
  if (n.includes("RESUMO")) return true;
  if (n.includes("PACIENTES")) return true;
  if (n.includes("EXAME(S)")) return true;
  if (n.includes("DATA DE IMPRESSAO")) return true;
  if (n.includes("USUARIO")) return true;

  return false;
}

function encontrarIndicePrimeiroExame(partes) {
  for (let i = 0; i < partes.length; i++) {
    const termo = corrigirExameOCR(partes[i]);

    if (examesSet.has(termo)) {
      return i;
    }
  }

  return -1;
}

// ======================================================
// 6. DADOS BASE
// ======================================================

const posto = extrairPosto(nomeArquivo, textoOCR);
const dataPadrao = extrairData(nomeArquivo, textoOCR);

const pacientes = [];
const chavesIncluidas = new Set();

function adicionarPaciente(dataLinha, codigo, paciente, examesBruto) {
  dataLinha = limpar(dataLinha);
  codigo = limpar(codigo);
  paciente = limpar(paciente);
  examesBruto = limpar(examesBruto);

  if (!ehDataBR(dataLinha)) return;
  if (!ehCodigo(codigo)) return;
  if (!ehNomePaciente(paciente)) return;

  const chave = `${dataLinha}|${codigo}|${normalizar(paciente)}`;
  if (chavesIncluidas.has(chave)) return;

  const exames = examesBruto
    ? separarExames(examesBruto, posto)
    : [];

  pacientes.push({
    data: dataLinha || dataPadrao,
    codigo,
    PACIENTE: normalizar(paciente),
    EXAMES: exames,
    EXAMES_BRUTO: examesBruto
  });

  chavesIncluidas.add(chave);
}

// ======================================================
// 7. PROCESSA TABELAS COM PIPE
// ======================================================

const linhas = textoOCR
  .split(/\r?\n/)
  .map(l => limpar(l))
  .filter(Boolean);

for (const linha of linhas) {
  if (linhaIgnorada(linha)) continue;
  if (!linha.includes("|")) continue;

  let cols = linha.split("|").map(c => limpar(c));

  if (cols[0] === "") cols.shift();
  if (cols[cols.length - 1] === "") cols.pop();

  if (cols.length < 3) continue;

  const dataLinha = limpar(cols[0]);
  const codigo = limpar(cols[1]);
  const paciente = limpar(cols[2]);
  const examesBruto = limpar(cols.slice(3).join(" "));

  adicionarPaciente(dataLinha, codigo, paciente, examesBruto);
}

// ======================================================
// 8. PROCESSA REGISTROS SIMPLES COM REGEX GLOBAL
// Captura cada bloco:
// DATA CODIGO CONTEUDO até a próxima DATA CODIGO
// ======================================================

const textoParaRegex = textoOCR
  .replace(/\|/g, " ")
  .replace(/\r/g, "\n");

const regexRegistro = /(\d{2}\/\d{2}\/\d{4})\s+(\d{4,})\s+([\s\S]*?)(?=\s+\d{2}\/\d{2}\/\d{4}\s+\d{4,}\s+|\s+Resumo:|\s+Data de impressão:|\s+Usuário:|$)/gi;

let match;

while ((match = regexRegistro.exec(textoParaRegex)) !== null) {
  const dataLinha = limpar(match[1]);
  const codigo = limpar(match[2]);
  let resto = limpar(match[3]);

  if (!resto) continue;

  resto = resto
    .replace(/\bResumo:.*$/i, "")
    .replace(/\bData de impressão:.*$/i, "")
    .replace(/\bUsuário:.*$/i, "")
    .trim();

  const partes = resto
    .split(/\s+/)
    .map(p => limpar(p))
    .filter(Boolean);

  if (partes.length === 0) continue;

  const indicePrimeiroExame = encontrarIndicePrimeiroExame(partes);

  let paciente = "";
  let examesBruto = "";

  if (indicePrimeiroExame === -1) {
    paciente = partes.join(" ");
    examesBruto = "";
  } else {
    paciente = partes.slice(0, indicePrimeiroExame).join(" ");
    examesBruto = partes.slice(indicePrimeiroExame).join(" ");
  }

  adicionarPaciente(dataLinha, codigo, paciente, examesBruto);
}

// ======================================================
// 9. RETORNO FINAL
// ======================================================

if (pacientes.length === 0) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum paciente foi extraído do OCR.",
        posto,
        data: dataPadrao,
        nomeArquivo,
        debug: {
          totalItensRecebidos: todosItens.length,
          totalExamesConhecidos: examesSet.size,
          temBHCG: examesSet.has("BHCG"),
          temCTFT: examesSet.has("CTFT"),
          temCTF: examesSet.has("CTF"),
          totalLinhas: linhas.length,
          primeirasLinhas: linhas.slice(0, 30),
          textoNormalizadoInicio: textoOCR.slice(0, 1000)
        }
      }
    }
  ];
}

return pacientes.map((p, index) => ({
  json: {
    sucesso: true,
    categoria: "(+)COMPUTADOR DO POSTO",
    PACIENTE: p.PACIENTE,
    EXAMES: p.EXAMES,
    EXAMES_TEXTO: p.EXAMES.join(", "),
    QTD_EXAMES: p.EXAMES.length,
    VALOR: 0,
    posto,
    data: p.data || dataPadrao,
    codigo: p.codigo,
    EXAMES_BRUTO: p.EXAMES_BRUTO,
    _idx: index + 1,
    _totalPacientes: pacientes.length,
    _totalExamesConhecidos: examesSet.size
  }
}));

// ======================================================
// EXTRATOR OCR - RECIBO DE PAGAMENTO AO MÉDICO
// ✅ Lê retorno do Mistral OCR
// ✅ Extrai pacientes da tabela markdown
// ✅ Retorna 1 item por paciente
// ✅ Extrai atendimento, paciente, procedimentos, convênio e valor médico
// ✅ Extrai médico, recibo, data do caixa, data de pagamento e forma de pagamento
// ======================================================

// ======================================================
// 1. PEGA INPUT
// ======================================================

const entrada = $input.first().json;

// Caso o input venha como array, pega o primeiro item
const input = Array.isArray(entrada) ? entrada[0] : entrada;

// ======================================================
// 2. PEGA TEXTO OCR
// ======================================================

const textoOCR = String(
  input.extractedText ||
  input.text ||
  input.markdown ||
  input.output ||
  input.response ||
  (
    Array.isArray(input.pages)
      ? input.pages.map(p => p.markdown || "").join("\n")
      : ""
  ) ||
  ""
);

if (!textoOCR.trim()) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum texto OCR encontrado."
      }
    }
  ];
}

// ======================================================
// 3. FUNÇÕES AUXILIARES
// ======================================================

function limpar(valor) {
  return String(valor ?? "")
    .replace(/\u00A0/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizar(valor) {
  return limpar(valor)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase();
}

function converterValor(valor) {
  let v = limpar(valor);

  if (!v) return 0;

  v = v
    .replace(/R\$/gi, "")
    .replace(/\s+/g, "")
    .trim();

  // Caso venha no formato brasileiro: 202,60
  if (/^\d{1,3}(\.\d{3})*,\d{2}$/.test(v)) {
    v = v.replace(/\./g, "").replace(",", ".");
  }

  // Caso venha como 35.50, mantém
  const numero = Number(v);

  return Number.isFinite(numero) ? numero : 0;
}

function separarProcedimentos(textoProcedimentos) {
  const texto = limpar(textoProcedimentos);

  if (!texto) return [];

  const procedimentos = [];
  let atual = "";
  let nivelParenteses = 0;

  for (let i = 0; i < texto.length; i++) {
    const char = texto[i];

    if (char === "(") {
      nivelParenteses++;
      atual += char;
      continue;
    }

    if (char === ")") {
      nivelParenteses = Math.max(0, nivelParenteses - 1);
      atual += char;
      continue;
    }

    // Se for vírgula fora de parênteses, separa o procedimento
    if (char === "," && nivelParenteses === 0) {
      const proc = limpar(atual);
      if (proc) procedimentos.push(proc);
      atual = "";
      continue;
    }

    atual += char;
  }

  const ultimo = limpar(atual);
  if (ultimo) procedimentos.push(ultimo);

  return procedimentos
    .map(p => limpar(p).toUpperCase())
    .filter(Boolean);
}

function extrairMedico(texto) {
  const m = texto.match(/M[eé]dico:\s*([^\n\r]+)/i);
  return m ? limpar(m[1]).toUpperCase() : "";
}

function extrairNumeroRecibo(texto) {
  const m = texto.match(/Recibo\s+nr\.?\s*([0-9]+)/i);
  return m ? limpar(m[1]) : "";
}

function extrairDataCaixa(texto) {
  const m = texto.match(/Data\s+do\s+Caixa:\s*(\d{2}\/\d{2}\/\d{4})/i);
  return m ? limpar(m[1]) : "";
}

function extrairDataPagamento(texto) {
  const m = texto.match(/Data\s+de\s+Pagamento:\s*(\d{2}\/\d{2}\/\d{4})\s+(\d{2}:\d{2})h?/i);

  return {
    dataPagamento: m ? limpar(m[1]) : "",
    horaPagamento: m ? limpar(m[2]) : ""
  };
}

function extrairFormaPagamento(texto) {
  const m = texto.match(/Forma\s+de\s+Pagamento:\s*([^\n\r]+)/i);
  return m ? limpar(m[1]).toUpperCase() : "";
}

function ehLinhaPaciente(cols) {
  if (cols.length < 5) return false;

  const atendimento = limpar(cols[0]);
  const paciente = limpar(cols[1]);
  const procedimentos = limpar(cols[2]);
  const convenio = limpar(cols[3]);
  const valor = limpar(cols[4]);

  if (!/^\d+$/.test(atendimento)) return false;
  if (!paciente || paciente.length < 5) return false;
  if (/\d/.test(paciente)) return false;
  if (!procedimentos) return false;
  if (!convenio) return false;
  if (!valor) return false;

  const nPaciente = normalizar(paciente);

  const bloqueados = [
    "PACIENTE",
    "TOTAL",
    "TAXAS",
    "LANCAMENTO",
    "ATEND",
    "PROCEDIMENTOS",
    "CONVENIO",
    "VALOR MEDICO",
    "QTD VOLTA",
    "QTD ATEND"
  ];

  if (bloqueados.some(p => nPaciente.includes(p))) return false;

  return true;
}

// ======================================================
// 4. EXTRAI DADOS GERAIS DO RECIBO
// ======================================================

const medico = extrairMedico(textoOCR);
const numeroRecibo = extrairNumeroRecibo(textoOCR);
const dataCaixa = extrairDataCaixa(textoOCR);
const { dataPagamento, horaPagamento } = extrairDataPagamento(textoOCR);
const formaPagamento = extrairFormaPagamento(textoOCR);

// Usa a data do caixa como data principal.
// Se não encontrar, usa a data de pagamento.
const data = dataCaixa || dataPagamento;

// ======================================================
// 5. LÊ LINHAS DA TABELA
// ======================================================

const linhas = textoOCR
  .split(/\r?\n/)
  .map(l => limpar(l))
  .filter(Boolean);

const pacientes = [];

for (const linha of linhas) {
  if (!linha.includes("|")) continue;

  let cols = linha.split("|").map(c => limpar(c));

  // Remove coluna vazia no início e no final quando a tabela começa/termina com |
  if (cols[0] === "") cols.shift();
  if (cols[cols.length - 1] === "") cols.pop();

  // Ignora linha separadora markdown
  if (cols.some(c => /^-+$/.test(c.replace(/\s/g, "")))) continue;

  if (!ehLinhaPaciente(cols)) continue;

  const atendimento = limpar(cols[0]);
  const paciente = limpar(cols[1]).toUpperCase();
  const procedimentosBruto = limpar(cols[2]);
  const convenio = limpar(cols[3]).toUpperCase();
  const valorMedico = converterValor(cols[4]);

  const exames = separarProcedimentos(procedimentosBruto);

  pacientes.push({
    atendimento,
    PACIENTE: paciente,
    EXAMES: exames,
    EXAMES_TEXTO: exames.join(", "),
    QTD_EXAMES: exames.length,
    CONVENIO: convenio,
    VALOR: valorMedico
  });
}

// ======================================================
// 6. SE NÃO ENCONTRAR PACIENTES
// ======================================================

if (pacientes.length === 0) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum paciente foi extraído da tabela do recibo.",
        medico,
        numeroRecibo,
        data,
        dataCaixa,
        dataPagamento,
        horaPagamento,
        formaPagamento,
        debug: {
          totalLinhas: linhas.length,
          linhasComPipe: linhas.filter(l => l.includes("|")).length,
          primeirasLinhasComPipe: linhas.filter(l => l.includes("|")).slice(0, 10)
        }
      }
    }
  ];
}

// ======================================================
// 7. RETORNO FINAL
// ======================================================

return pacientes.map((p, index) => ({
  json: {
    sucesso: true,
    categoria: "RECIBO DE PAGAMENTO AO MÉDICO",

    medico,
    numeroRecibo,
    data,
    dataCaixa,
    dataPagamento,
    horaPagamento,
    formaPagamento,

    atendimento: p.atendimento,
    PACIENTE: p.PACIENTE,
    EXAMES: p.EXAMES,
    EXAMES_TEXTO: p.EXAMES_TEXTO,
    QTD_EXAMES: p.QTD_EXAMES,
    CONVENIO: p.CONVENIO,
    VALOR: p.VALOR,

    _idx: index + 1,
    _totalPacientes: pacientes.length
  }
}));
